from typing import Dict, List, Optional

class TrieNode:
    """A node in the Trie data structure."""
    def __init__(self):
        self.children: Dict[str, 'TrieNode'] = {}
        self.is_end_of_word: bool = False

class Trie:
    """
    A Trie (prefix tree) data structure for efficient string storage and retrieval.

    Supports insertion of words, checking for word existence, and checking for prefixes.
    This utility is extremely useful in problems involving dictionaries, autocomplete,
    spell checkers, and prefix-based string searching.
    It covers topics like Trie, String manipulation, and uses Hash Tables (dictionaries)
    internally for efficient child lookup.
    """

    def __init__(self):
        self.root = TrieNode()

    def insert(self, word: str) -> None:
        """
        Inserts a word into the Trie.

        Args:
            word: The string word to insert.
        """
        node = self.root
        for char in word:
            if char not in node.children:
                node.children[char] = TrieNode()
            node = node.children[char]
        node.is_end_of_word = True

    def _search_node(self, prefix: str) -> Optional[TrieNode]:
        """
        Helper method to traverse the Trie for a given prefix.

        Args:
            prefix: The prefix string to search for.

        Returns:
            The TrieNode corresponding to the end of the prefix if found,
            otherwise None.
        """
        node = self.root
        for char in prefix:
            if char not in node.children:
                return None
            node = node.children[char]
        return node

    def search_word(self, word: str) -> bool:
        """
        Checks if a complete word exists in the Trie.

        Args:
            word: The string word to search for.

        Returns:
            True if the word is found, False otherwise.
        """
        node = self._search_node(word)
        return node is not None and node.is_end_of_word

    def starts_with_prefix(self, prefix: str) -> bool:
        """
        Checks if there is any word in the Trie that starts with the given prefix.

        Args:
            prefix: The string prefix to check.

        Returns:
            True if any word starts with the prefix, False otherwise.
        """
        return self._search_node(prefix) is not None

