def sieve_of_eratosthenes(limit: int) -> List[bool]:
    """
    Generates a boolean list indicating primality for numbers up to a given limit
    using the Sieve of Eratosthenes algorithm.

    This is an extremely useful utility function in competitive programming and
    algorithmic problems involving number theory, prime factorization, and modular
    arithmetic. It efficiently precomputes primality for a range of numbers.
    It directly relates to Math and Array topics.

    The list `is_prime[i]` will be True if `i` is a prime number, False otherwise.
    The list is 0-indexed, so `is_prime[0]` and `is_prime[1]` will be False.

    Args:
        limit: An integer representing the upper bound (inclusive) for finding primes.
               Must be non-negative.

    Returns:
        A list of booleans where `is_prime[i]` is True if `i` is prime, False otherwise.

    Raises:
        ValueError: If limit is negative.
    """
    if limit < 0:
        raise ValueError("Limit must be a non-negative integer.")

    if limit < 2:
        return [False] * (limit + 1)

    is_prime: List[bool] = [True] * (limit + 1)
    is_prime[0] = False  # 0 is not prime
    is_prime[1] = False  # 1 is not prime

    # We only need to check factors up to sqrt(limit)
    # because if n = a * b, and a > sqrt(n), then b must be < sqrt(n).
    # So one of the factors will always be <= sqrt(n).
    p = 2
    while p * p <= limit:
        # If is_prime[p] is still True, then it is a prime
        if is_prime[p]:
            # Mark all multiples of p greater than or equal to p*p as not prime.
            # Multiples less than p*p would have already been marked by smaller primes.
            for multiple in range(p * p, limit + 1, p):
                is_prime[multiple] = False
        p += 1

    return is_prime

